#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    printf("Enter size of array: ");
    scanf("%d", &n);

    // Dynamic allocation using malloc
    int *arr = (int*)malloc(n * sizeof(int));

    if (arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Accept elements
    printf("Enter %d elements: ", n);
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    // Display elements
    printf("Array elements: ");
    for (int i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }

    // Free allocated memory
    free(arr);

    return 0;
}

#include <stdio.h>
#include <math.h>

#define MAX_DEGREE 100

void createPolynomial(int poly[], int degree) {
    printf("Enter coefficients from constant to highest degree:\n");
    for (int i = 0; i <= degree; i++) {
        printf("Coefficient of x^%d: ", i);
        scanf("%d", &poly[i]);
    }
}

int evaluatePolynomial(int poly[], int degree, int x) {
    int result = 0;
    for (int i = 0; i <= degree; i++) {
        result += poly[i] * pow(x, i);
    }
    return result;
}

void displayPolynomial(int poly[], int degree) {
    printf("Polynomial: ");
    for (int i = degree; i >= 0; i--) {
        if (poly[i] != 0) {
            printf("%dx^%d ", poly[i], i);
            if (i > 0) printf("+ ");
        }
    }
    printf("\n");
}

int main() {
    int poly[MAX_DEGREE];
    int degree, x;

    printf("Enter degree of polynomial: ");
    scanf("%d", &degree);

    createPolynomial(poly, degree);
    displayPolynomial(poly, degree);

    printf("Enter value of x: ");
    scanf("%d", &x);

    printf("Result at x=%d: %d\n", x, evaluatePolynomial(poly, degree, x));

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Term {
    int coefficient;
    int exponent;
};

struct Polynomial {
    int numTerms;
    struct Term *terms;
};

void createPolynomial(struct Polynomial *p) {
    printf("Enter number of non-zero terms: ");
    scanf("%d", &p->numTerms);

    p->terms = (struct Term*)malloc(p->numTerms * sizeof(struct Term));

    printf("Enter coefficient and exponent for each term:\n");
    for (int i = 0; i < p->numTerms; i++) {
        scanf("%d %d", &p->terms[i].coefficient, &p->terms[i].exponent);
    }
}

void displayPolynomial(struct Polynomial *p) {
    printf("Polynomial: ");
    for (int i = 0; i < p->numTerms; i++) {
        printf("%dx^%d ", p->terms[i].coefficient, p->terms[i].exponent);
        if (i < p->numTerms - 1) printf("+ ");
    }
    printf("\n");
}

int main() {
    struct Polynomial p;
    createPolynomial(&p);
    displayPolynomial(&p);
    free(p.terms);
    return 0;
}

class DynamicArray:
    def __init__(self, capacity=1):
        self.capacity = capacity
        self.size = 0
        self.array = [None] * self.capacity

    def append(self, element):
        # Resize if array is full
        if self.size == self.capacity:
            self.resize(2 * self.capacity)
        self.array[self.size] = element
        self.size += 1

    def resize(self, new_capacity):
        # Create new array and copy elements
        new_array = [None] * new_capacity
        for i in range(self.size):
            new_array[i] = self.array[i]
        self.array = new_array
        self.capacity = new_capacity

    def get(self, index):
        if 0 <= index < self.size:
            return self.array[index]
        return None

    def length(self):
        return self.size

    def display(self):
        print("Array:", self.array[:self.size])

# Usage
arr = DynamicArray()
for i in range(20):
    arr.append(i * 10)
    print(f"Size: {arr.size}, Capacity: {arr.capacity}")

arr.display()
print(f"Element at index 5: {arr.get(5)}")
